class Data21(BaseModel):
    """
    An order form is a form presented to customers when purchasing tickets or
    other products from a host, as part of the checkout flow.
    Order forms have two sections: a "buyer" section whose elements appear once
    for the whole order, and a "ticket-holder"/"attendees" section whose elements
    appear once for each ticket in the order, to collect multiple responses when
    an order represents multiple event attendees.
    Order forms can populate CRM properties on contacts, orders, and tickets.
    Form submissions can trigger workflows, and their questions & answers can be
    referenced in workflow actions.
    """

    model_config = ConfigDict(
        extra="forbid",
    )
    id: str = Field(..., description="The form's ID.")
    name: str = Field(..., description="The form's display name.")
    nameHidden: bool | None = Field(
        None,
        description="If true, the name of the form will not be shown to respondents.",
    )
    ownerId: str = Field(..., description="The ID of the host who owns this form.")
    status: Status12 = Field(
        ...,
        description="Determines the status of the form.\n- draft: the form cannot be accessed directly at its URL, and may not show up to the organizer in tables by default\n- active: the form can be accessed by its URL, and appears to the organizer in all tables\n- archived: for all intents and purposes, the form is deleted, but can still be accessed and restored in the forms dashboard",
    )
    rows: list[Row3] = Field(
        ...,
        description="A form's layout consists of rows, each with one or more columns. Each column\ncontains a single form element. Form layouts determine the order that the\nform's elements are displayed in, not the order of the form's `elements`\narray.",
    )
    submitButtonText: str = Field(
        ...,
        description='Text displayed in the form\'s submission button. Typically, "Submit" is the default.',
    )
    submitButtonWidth: SubmitButtonWidth = Field(
        ...,
        description='Whether the form\'s submission button should shrink to fit its label ("auto"), or fill its container ("fill").',
    )
    submitButtonAlign: SubmitButtonAlign | None = Field(
        None,
        description='If `submitButtonWidth` is "auto", this determines how the submission button is horizontally aligned.',
    )
    type: Type50
    elements: list[
        Elements39
        | Elements40
        | Elements41
        | Elements42
        | Elements43
        | Elements44
        | Elements45
        | Elements46
        | Elements47
        | Elements48
        | Elements49
        | Elements50
        | Elements51
    ] = Field(
        ...,
        description="Form questions (input fields) or static elements (text blocks, images, etc.)",
    )
    attendeeRowsStart: float = Field(
        ...,
        description='The index of the first row in the form\'s `rows` array which is in the\n"ticket-holder" section.',
    )


